data.query:
query Metaobjects($type: String!, $first: Int, $after: String, $sortKey: String, $reverse: Boolean) {
                    metaobjects(type: $type, first: $first, after: $after, sortKey: $sortKey, reverse: $reverse) {
                        nodes {
                            id
                            handle
                            type
                            displayName
                            updatedAt
                            createdAt
                            fields {
                                key
                                value
                                jsonValue
                                type
                            }
                        }
                        pageInfo {
                            hasNextPage
                            endCursor
                        }
                    }
                }
